(() => {
  if ('scrollRestoration' in history) {
    history.scrollRestoration = 'manual';
  }
  const HAS_HASH_AT_BOOT = !!location.hash;
  if (HAS_HASH_AT_BOOT) {
    try {
      document.documentElement.style.scrollBehavior = 'auto';
    } catch {}
    window.scrollTo(0, 0);
  }

  const INITIAL_HASH = location.hash; // збережемо стартовий хеш як був
  let suppressUrlSync = !!INITIAL_HASH; // поки true — updateActiveSection не міняє URL
  let isResizing = false;
  let fitScaleLocked = false;
  const MOBILE_TABLET_MAX_W = 1140;
  let keyboardWasOpen = false;
  let keyboardReadyAt = 0;
  let keyboardBaseH = 0;
  let keyboardMinH = null;

  window.__swiperGestureLock = false;
  function isSwiperGestureLocked() {
    return window.__swiperGestureLock === true;
  }

  // ---------- НАЛАШТУВАННЯ ----------
  const TOP_GAP = 24;
  const BOTTOM_GAP = 16;
  const MIN_WHEEL = 15; // мінімальний нормалізований імпульс для одного кроку
  const SECTION_MISALIGN_PX = 32;
  const REPAIR_SCROLL_MS = 80;

  document.documentElement.style.setProperty(
    '--app-h',
    `${window.innerHeight}px`,
  );

  // ---------- УТИЛІТИ ----------
  const BREATH_DUR_MS = readCssTimeVar('--breath-dur', 900);

  const HEADER_H = (() => {
    const raw = getComputedStyle(document.documentElement)
      .getPropertyValue('--header-h')
      .trim();
    const n = parseFloat(raw);
    return Number.isFinite(n) ? n : 88;
  })();

  function readCssTimeVar(varName, fallbackMs) {
    const raw = getComputedStyle(document.documentElement)
      .getPropertyValue(varName)
      .trim();
    if (!raw) return fallbackMs;
    const isSec = raw.endsWith('s') && !raw.endsWith('ms');
    const num = parseFloat(raw);
    if (!Number.isFinite(num)) return fallbackMs;
    return Math.round(isSec ? num * 1000 : num);
  }

  function easeInOutCubic(t) {
    return t < 0.5 ? 4 * t * t * t : 1 - Math.pow(-2 * t + 2, 3) / 2;
  }

  function smoothScrollTo(targetY, dur, onProgress) {
    const startY = window.scrollY;
    const dist = targetY - startY;
    const start = performance.now();

    return new Promise(resolve => {
      function step(now) {
        const p = Math.min((now - start) / dur, 1);
        const eased = easeInOutCubic(p);
        const y = startY + dist * eased;
        window.scrollTo(0, Math.round(y));
        if (onProgress) onProgress(eased);
        if (p < 1) requestAnimationFrame(step);
        else resolve();
      }
      requestAnimationFrame(step);
    });
  }

  //стартовий перехід на хеш
  function bootToHashIfAny() {
    const id = INITIAL_HASH;
    if (!id || id.length <= 1) {
      suppressUrlSync = false;
      document.documentElement.classList.remove('fp-preboot');
      return;
    }

    const target = document.querySelector(id);
    if (!target) {
      suppressUrlSync = false;
      document.documentElement.classList.remove('fp-preboot');
      return;
    }

    const sec = target.closest('.section') || target;
    const idx = sections.indexOf(sec);
    if (idx < 0) {
      suppressUrlSync = false;
      document.documentElement.classList.remove('fp-preboot');
      return;
    }

    init();
    current = idx;
    setActive(idx);
    window.scrollTo({ top: stops[idx], behavior: 'auto' });
    updateActiveSection();

    suppressUrlSync = false;
  }

  // Нормалізація колеса миші: pixel/line/page -> px
  function normWheelDY(e) {
    const LINE = 16;
    const PAGE = window.innerHeight;
    let dy = e.deltaY;
    if (e.deltaMode === 1) dy *= LINE;
    else if (e.deltaMode === 2) dy *= PAGE;
    return dy;
  }

  function clamp(n, min, max) {
    return Math.max(min, Math.min(max, n));
  }

  //хелпер для оновлення URL за індексом секції
  function idHashForIndex(i) {
    if (i < 0 || i >= sections.length) return '';
    const el = sections[i];
    return el?.id ? `#${el.id}` : '';
  }

  // без створення нової історії — лише заміна поточного запису
  function replaceUrlForIndex(i) {
    if (suppressUrlSync || isResizing) return;

    const hash = idHashForIndex(i);
    if (!hash || hash === location.hash) return;

    history.replaceState(null, '', hash);
  }

  function isMobileOrTablet() {
    return window.innerWidth <= MOBILE_TABLET_MAX_W;
  }

  function getDeviceSizeKey() {
    const sw = window.screen?.width || 0;
    const sh = window.screen?.height || 0;
    const o = window.screen?.orientation?.type || '';
    return `${Math.min(sw, sh)}x${Math.max(sw, sh)}|${o}`;
  }

  let lastDeviceSizeKey = getDeviceSizeKey();

  function shouldRecalculateScale() {
    const nextKey = getDeviceSizeKey();
    if (nextKey === lastDeviceSizeKey) return false;
    lastDeviceSizeKey = nextKey;
    return true;
  }

  function getFixedIndexForResize() {
    const currentIdx = clamp(current, 0, sections.length - 1);
    const id = (location.hash || '').trim();
    if (id.length <= 1) return currentIdx;

    const target = document.querySelector(id);
    const sec = target?.closest('.section') || target;
    const hashIdx = sections.indexOf(sec);
    if (hashIdx < 0) return currentIdx;

    if (!stops.length) return hashIdx;

    const y = Math.round(window.scrollY);
    const dHash = Math.abs((stops[hashIdx] ?? 0) - y);
    const dCurrent = Math.abs((stops[currentIdx] ?? 0) - y);

    // якщо hash трохи відстає, беремо current
    return dHash <= dCurrent + 20 ? hashIdx : currentIdx;
  }

  function isFormFieldFocused() {
    const el = document.activeElement;
    return (
      !!el && el.matches('input, textarea, select, [contenteditable="true"]')
    );
  }

  function isContactInputModalOpen() {
    return window.__contactInputModalOpen === true;
  }

  function isPhoneCountryDropdownOpen() {
    return window.__phoneCountryDropdownOpen === true;
  }

  function isMobileMenuOpen() {
    return document.body.classList.contains('is-scroll-disabled');
  }

  function shouldPauseFullpage() {
    return (
      isContactInputModalOpen() ||
      isPhoneCountryDropdownOpen() ||
      isMobileMenuOpen() ||
      isFocusedFieldInsideContactForm()
    );
  }

  function syncToFixedSectionAfterViewportChange(forceRefit = false) {
    if (shouldPauseFullpage()) return;

    const fixedIndex = getFixedIndexForResize();
    isResizing = true;

    try {
      if (forceRefit) {
        applyFitScalesOnce(true);
      } else if (shouldRecalculateScale()) {
        applyFitScalesOnce(true);
      }

      init();
      current = clamp(fixedIndex, 0, stops.length - 1);
      window.scrollTo({ top: stops[current], behavior: 'auto' });
      setActive(current);
      replaceUrlForIndex(current);
    } finally {
      isResizing = false;
    }
  }

  // ---------- КЕШ ДОМ ЕЛЕМЕНТІВ ----------
  const sections = Array.from(document.querySelectorAll('.section'));
  const headerLinks = Array.from(
    document.querySelectorAll('header a[href^="#"]'),
  );

  // ---------- СТАН ----------
  let stops = [];
  let current = 0;
  let locked = false; // «фіксація»: поки true — імпульси ігноряться
  let resizeTimer = null;
  let scrollTmr = null;
  let startY = null;
  let contactInputJumpProbe = null;
  let contactModalSnapTmr = null;
  let sectionRepairTmr = null;
  let imageLoadUpdateRaf = 0;

  function scheduleImageLoadRecalc() {
    if (imageLoadUpdateRaf) return;
    imageLoadUpdateRaf = requestAnimationFrame(() => {
      imageLoadUpdateRaf = 0;
      init();
      updateActiveSection();
    });
  }

  function isFormField(el) {
    return (
      !!el &&
      el.matches &&
      el.matches('input, textarea, select, [contenteditable="true"]')
    );
  }

  function blurFocusedFormField() {
    const el = document.activeElement;
    if (el && el.matches('input, textarea, select, [contenteditable="true"]')) {
      el.blur();
    }
  }

  function blurOnKeyboardClose() {
    if (!isMobileOrTablet()) return;
    if (!isFocusedFieldInsideContactForm()) return;

    const vv = window.visualViewport;
    if (!vv) return;

    const h = vv.height;
    keyboardMinH = Math.min(keyboardMinH ?? h, h);

    // Даємо клавіатурі стартувати
    if (Date.now() < keyboardReadyAt) return;

    // Вважаємо, що клава відкрита, якщо viewport помітно зменшився
    const openedByDelta = keyboardBaseH - keyboardMinH >= 18;
    if (openedByDelta) keyboardWasOpen = true;

    // Закрита, коли майже повернулись до базової висоти
    if (
      keyboardWasOpen &&
      h >= keyboardBaseH - 40 &&
      Date.now() >= keyboardReadyAt
    ) {
      blurFocusedFormField();
      clearContactInputJumpProbe();
      keyboardWasOpen = false;
      keyboardReadyAt = 0;
      keyboardBaseH = 0;
      keyboardMinH = null;
    }
  }

  function snapToContactSectionNoAnim() {
    const contactIdx = sections.findIndex(s => s.id === 'contact-section');
    if (contactIdx < 0) return;

    init();
    current = clamp(contactIdx, 0, stops.length - 1);
    window.scrollTo({ top: stops[current], behavior: 'auto' });
    setActive(current);
    replaceUrlForIndex(current);
  }

  function queueSnapToContactSection(delay = 0) {
    clearTimeout(contactModalSnapTmr);
    contactModalSnapTmr = setTimeout(() => {
      snapToContactSectionNoAnim();
    }, delay);
  }

  function getEffectiveViewportTop() {
    const vvTop = Math.round(window.visualViewport?.pageTop ?? 0);
    return Math.max(Math.round(window.scrollY), vvTop);
  }

  function getEffectiveViewportHeight() {
    return Math.max(
      1,
      Math.round(window.visualViewport?.height ?? window.innerHeight),
    );
  }

  function getBreathRectForIndex(targetIdx) {
    if (targetIdx < 0 || targetIdx >= sections.length) return null;
    const sec = sections[targetIdx];
    if (!sec) return null;

    const breath = sec.querySelector('.section__breath') || sec;
    const rect = breath.getBoundingClientRect();
    if (!Number.isFinite(rect.top) || rect.height <= 0) return null;

    return rect;
  }

  function isSectionPlacementBroken(targetIdx) {
    if (targetIdx < 0 || targetIdx >= sections.length) return false;

    const rect = getBreathRectForIndex(targetIdx);
    const viewportH = getEffectiveViewportHeight();

    // Основна перевірка: центр .section__breath проти центру viewport
    // Лише для секцій, які приблизно вміщаються у viewport (щоб не ловити false positive)
    if (rect && (targetIdx === 1 || rect.height <= viewportH * 1.15)) {
      const breathCenter = rect.top + rect.height / 2;
      const viewportCenter = viewportH / 2;
      if (Math.abs(breathCenter - viewportCenter) > SECTION_MISALIGN_PX)
        return true;
    }

    // Fallback: координати скролу
    if (!stops.length || !Number.isFinite(stops[targetIdx])) return false;
    const expectedY = Math.round(stops[targetIdx]);
    const actualY = getEffectiveViewportTop();
    return Math.abs(actualY - expectedY) > SECTION_MISALIGN_PX;
  }

  function repairSectionPlacementIfBroken(reason = '') {
    if (locked || shouldPauseFullpage()) return false;
    if (!stops.length) init();

    const targetIdx = clamp(getFixedIndexForResize(), 0, sections.length - 1);
    if (!isSectionPlacementBroken(targetIdx)) return false;

    isResizing = true;
    try {
      current = clamp(targetIdx, 0, stops.length - 1);
      window.scrollTo({ top: stops[current], behavior: 'smooth' });

      setTimeout(() => {
        setActive(current);
        replaceUrlForIndex(current);
      }, REPAIR_SCROLL_MS);
    } finally {
      isResizing = false;
    }

    return true;
  }

  function scheduleSectionPlacementRepair(delay = 0, reason = '') {
    clearTimeout(sectionRepairTmr);
    sectionRepairTmr = setTimeout(() => {
      // даємо layout стабілізуватись перед фінальною перевіркою
      requestAnimationFrame(() => {
        requestAnimationFrame(() => {
          repairSectionPlacementIfBroken(reason);
        });
      });
    }, delay);
  }

  function armContactInputJumpProbe(field) {
    if (!isMobileOrTablet()) return;
    if (window.__contactInputModalModeEnabled === true) return;
    if (!field || !isFormField(field)) return;

    const contactIdx = sections.findIndex(s => s.id === 'contact-section');
    if (contactIdx < 0) return;

    const contactEl = sections[contactIdx];
    const contactTop = Math.max(0, Math.round(contactEl.offsetTop));
    const contactBottom = Math.max(
      contactTop,
      Math.round(contactEl.offsetTop + contactEl.offsetHeight),
    );

    contactInputJumpProbe = {
      field,
      contactIdx,
      contactTop,
      contactBottom,
      startY: Math.round(window.scrollY),
      startedAt: Date.now(),
      expiresAt: Date.now() + 1600,
    };
  }

  function clearContactInputJumpProbe() {
    contactInputJumpProbe = null;
  }

  function enableContactInputModalFallbackForProbe(reason = '') {
    const probe = contactInputJumpProbe;
    if (!probe) return false;

    const field = probe.field && probe.field.isConnected ? probe.field : null;
    const contactIdx = probe.contactIdx;

    contactInputJumpProbe = null;

    window.__contactInputModalModeEnabled = true;
    try {
      sessionStorage.setItem('contactInputModalMode', '1');
    } catch {}

    clearTimeout(resizeTimer);
    clearTimeout(scrollTmr);

    // Відкриваємо модалку одразу (щоб накрити екран), а вже потім тихо повертаємо contact під нею
    if (field && window.contactInputModalFallback?.openForField) {
      window.contactInputModalFallback.openForField(field);
    }

    blurFocusedFormField();

    // Повертаємо fullpage на contact вже під модалкою (користувач цього майже не побачить)
    requestAnimationFrame(() => {
      snapToContactSectionNoAnim();
      setTimeout(() => snapToContactSectionNoAnim(), 90);
    });

    return true;
  }

  function detectContactInputJumpAndEnableFallback(reason = '') {
    const probe = contactInputJumpProbe;
    if (!probe) return;

    if (!isMobileOrTablet()) {
      clearContactInputJumpProbe();
      return;
    }

    if (window.__contactInputModalModeEnabled === true) {
      clearContactInputJumpProbe();
      return;
    }

    if (Date.now() > probe.expiresAt) {
      clearContactInputJumpProbe();
      return;
    }

    // Важливо: реагуємо тільки поки фокус у контактній формі
    if (!isFocusedFieldInsideContactForm()) return;

    const vvTop = Math.round(window.visualViewport?.pageTop ?? 0);
    const y = Math.max(Math.round(window.scrollY), vvTop);

    const leftContactDown = y >= probe.contactBottom - 8;
    const leftContactUp = y < probe.contactTop - 8;
    const jumpedFar = Math.abs(y - probe.startY) >= 80;

    if ((leftContactDown || leftContactUp) && jumpedFar) {
      enableContactInputModalFallbackForProbe(reason);
    }
  }

  // ---------- ДОПОМОЖНІ ----------
  function computeStops() {
    return sections.map(s => Math.max(0, Math.round(s.offsetTop)));
  }

  function getClosestIndex(y) {
    let idx = 0,
      best = Infinity;
    for (let i = 0; i < stops.length; i++) {
      const d = Math.abs(stops[i] - y);
      if (d < best) {
        best = d;
        idx = i;
      }
    }
    return idx;
  }

  function init() {
    stops = computeStops();
    current = getClosestIndex(window.scrollY);
  }

  function indexOfAnchor(a) {
    const id = a.getAttribute('href');
    if (!id || id.length <= 1) return -1;
    const target = document.querySelector(id);
    if (!target) return -1;
    const sec = target.closest('.section') || target;
    return sections.indexOf(sec);
  }

  function setActiveHeader(idx) {
    headerLinks.forEach(a =>
      a.classList.toggle('is-active', indexOfAnchor(a) === idx),
    );
  }

  let sideNav = null;
  let sideItems = [];

  function buildSideNav() {
    if (sideNav) sideNav.remove();
    sideItems = [];

    const nav = document.createElement('nav');
    nav.className = 'side-nav';
    nav.setAttribute('aria-label', 'Section navigation');

    const ul = document.createElement('ul');
    ul.className = 'side-nav__list';

    sections.forEach((sec, i) => {
      const li = document.createElement('li');
      const btn = document.createElement('button');
      btn.type = 'button';
      btn.className = 'side-nav__btn';
      const label =
        sec.dataset.navTitle ||
        sec.querySelector('.section__title')?.textContent?.trim() ||
        `Section ${i + 1}`;
      btn.setAttribute('aria-label', label);
      btn.title = label;
      btn.addEventListener('click', () => {
        if (!locked) lockAndGo(i);
        // оновимо URL для глибокої навігації
        const id = sec.id ? `#${sec.id}` : '';
        if (id)
          (history.pushState(null, '', id),
            window.dispatchEvent(new HashChangeEvent('hashchange')));
      });
      li.appendChild(btn);
      ul.appendChild(li);
      sideItems.push(btn);
    });

    nav.appendChild(ul);
    document.body.appendChild(nav);
    sideNav = nav;
  }

  function setActiveSidebar(idx) {
    sideItems.forEach((b, i) => b.classList.toggle('is-active', i === idx));
  }

  function isFocusedFieldInsideContactForm() {
    const el = document.activeElement;
    const formEl = document.getElementById('contact-section-form');
    return !!(el && formEl && formEl.contains(el) && isFormField(el));
  }

  // --- Заморозка «дихання» у передостанній секції (без зміни масштабу) ---
  // Керування класом на <body>, щоб CSS теж знав, що ми на/біля футера
  function setActive(idx) {
    sections.forEach((s, i) => {
      const isActive = i === idx;
      s.classList.toggle('is-active', isActive);
      s.classList.toggle('is-leaving', !isActive);
    });

    setActiveSidebar(idx);
    setActiveHeader(idx);
  }

  function updateActiveSection() {
    if (shouldPauseFullpage()) return;
    if (locked) return;
    if (!stops.length) return;

    const y = getEffectiveViewportTop();
    const activeIdx = getClosestIndex(y);

    if (activeIdx !== current) {
      setActive(activeIdx);
      current = activeIdx; // sync active index
    }
    if (!suppressUrlSync) replaceUrlForIndex(current);
  }

  // ---------- FIT‑SCALE + компенсація падінга ----------
  function computeFitScaleFor(el) {
    const contentH = Math.max(el.scrollHeight, el.offsetHeight);
    const contentW = Math.max(el.scrollWidth, el.offsetWidth);

    const availH = Math.max(
      0,
      window.innerHeight - HEADER_H - TOP_GAP - BOTTOM_GAP,
    );
    const availW = Math.max(0, window.innerWidth);

    const scaleH = availH > 0 ? availH / contentH : 1;
    const scaleW = availW > 0 ? availW / contentW : 1;

    const s = Math.min(scaleH, scaleW, 1);
    return Math.max(s, 0.4);
  }

  function applyFitScales() {
    const updates = sections.map(sec => {
      const target = sec.querySelector('.section__scaling') || sec;

      if (sec.id === 'services-section' && window.innerWidth < 1140) {
        return { sec, target, scale: 1, padComp: 0 };
      }

      const scale = computeFitScaleFor(target);

      const cs = getComputedStyle(sec);
      const basePtVar = parseFloat(cs.getPropertyValue('--base-pt'));
      const basePt = Number.isFinite(basePtVar)
        ? basePtVar
        : parseFloat(cs.paddingTop) || 44;

      let padComp;
      if (scale < 1 && sec.classList.contains('hero-section')) {
        padComp = basePt;
      } else {
        padComp = scale < 1 ? basePt * (1 - scale) : 0;
      }

      return { sec, target, scale, padComp };
    });

    updates.forEach(({ sec, target, scale, padComp }) => {
      target.style.setProperty('--fit-scale', scale.toFixed(3));
      sec.style.setProperty('--pad-comp', `${padComp.toFixed(2)}px`);
    });
  }

  function applyFitScalesOnce(force = false) {
    if (fitScaleLocked && !force) return;
    applyFitScales();
    fitScaleLocked = true;
  }

  function ensureScalingWrappers() {
    sections.forEach(sec => {
      // 1) зовнішня обгортка під fit‑scale
      let scaling = sec.querySelector('.section__scaling');
      if (!scaling) {
        scaling = document.createElement('div');
        scaling.className = 'section__scaling';
        while (sec.firstChild) scaling.appendChild(sec.firstChild);
        sec.appendChild(scaling);
      }
      // 2) внутрішня обгортка під «дихання»
      if (!scaling.querySelector('.section__breath')) {
        const breath = document.createElement('div');
        breath.className = 'section__breath';
        while (scaling.firstChild) breath.appendChild(scaling.firstChild);
        scaling.appendChild(breath);
      }
    });
  }

  // ---------- ПЕРЕХІД МІЖ СЕКЦІЯМИ (ФІКСАЦІЯ) ----------
  function nextFrame() {
    return new Promise(r => requestAnimationFrame(() => r()));
  }

  async function lockAndGo(nextIndex) {
    if (isSwiperGestureLocked()) return;

    if (
      nextIndex < 0 ||
      nextIndex >= stops.length ||
      locked ||
      shouldPauseFullpage()
    )
      return;

    locked = true;

    current = nextIndex;
    setActive(nextIndex);

    const nextBreath = sections[nextIndex]?.querySelector('.section__breath');
    if (nextBreath) {
      void nextBreath.getBoundingClientRect();
    }

    await nextFrame();
    await smoothScrollTo(stops[nextIndex], BREATH_DUR_MS);

    replaceUrlForIndex(current);
    locked = false;
    updateActiveSection();

    // Telegram/iPhone: після завершення snap події resize/scroll можуть не прийти
    scheduleSectionPlacementRepair(0, 'lock-end');

    // Друга перевірка трохи пізніше, коли viewport "дихає" після анімації
    setTimeout(() => {
      if (locked || shouldPauseFullpage()) return;
      repairSectionPlacementIfBroken('lock-end-late');
    }, 180);
  }

  // ---------- ОБРОБКА ВВОДУ ----------
  function onWheel(e) {
    if (isSwiperGestureLocked()) return;
    if (shouldPauseFullpage()) return;
    if (e.ctrlKey || e.metaKey) return;
    if (locked) {
      e.preventDefault();
      return;
    }

    const dy = normWheelDY(e);
    if (Math.abs(dy) < MIN_WHEEL) return;

    e.preventDefault();

    if (dy > 0 && current < stops.length - 1) {
      lockAndGo(current + 1);
    } else if (dy < 0 && current > 0) {
      lockAndGo(current - 1);
    }
  }

  function onKey(e) {
    if (isSwiperGestureLocked()) return;
    if (shouldPauseFullpage()) return;

    const keys = [
      'ArrowDown',
      'PageDown',
      ' ',
      'ArrowUp',
      'PageUp',
      'Home',
      'End',
    ];
    if (locked && keys.includes(e.key)) {
      e.preventDefault();
      return;
    }

    if (['ArrowDown', 'PageDown', ' '].includes(e.key)) {
      e.preventDefault();
      if (current < stops.length - 1) lockAndGo(current + 1);
    } else if (['ArrowUp', 'PageUp'].includes(e.key)) {
      e.preventDefault();
      if (current > 0) lockAndGo(current - 1);
    } else if (e.key === 'Home') {
      e.preventDefault();
      lockAndGo(0);
    } else if (e.key === 'End') {
      e.preventDefault();
      lockAndGo(stops.length - 1);
    }
  }

  // Всі якірні посилання міняємо так, щоб НЕ було нативного стрибка,
  // а хеш оновлювався через history.pushState + штучний hashchange
  function wireAnchors() {
    document.querySelectorAll('a[href^="#"]').forEach(a => {
      a.addEventListener('click', e => {
        const id = a.getAttribute('href'); // типу "#about"
        if (!id || id.length <= 1) return;
        const target = document.querySelector(id);
        if (!target) return;

        e.preventDefault();
        history.pushState(null, '', id);
        window.dispatchEvent(new HashChangeEvent('hashchange')); // далі lockAndGo
      });
    });
  }

  function wireTouch() {
    window.addEventListener('touchstart', e => {
      if (isSwiperGestureLocked()) {
        startY = null;
        return;
      }
      if (shouldPauseFullpage()) {
        startY = null;
        return;
      }

      startY = e.touches[0].clientY;
    });

    window.addEventListener(
      'touchmove',
      e => {
        if (isSwiperGestureLocked()) {
          startY = null;
          return;
        }
        if (shouldPauseFullpage()) {
          startY = null;
          return;
        }

        if (startY == null) return;
        if (locked) return;

        const dy = startY - e.touches[0].clientY;
        if (Math.abs(dy) < 50) return;

        if (dy > 0 && current < stops.length - 1) {
          lockAndGo(current + 1);
        } else if (dy < 0 && current > 0) {
          lockAndGo(current - 1);
        }
        startY = null;
      },
      { passive: true },
    );

    document.addEventListener(
      'pointerdown',
      e => {
        const target = e.target instanceof Element ? e.target : null;
        if (!target) return;

        const formEl = document.getElementById('contact-section-form');
        const field = target.closest(
          'input, textarea, select, [contenteditable="true"]',
        );

        // тап по полю — не blur
        if (field) {
          if (!isMobileOrTablet() || !formEl || !formEl.contains(field)) return;

          clearTimeout(resizeTimer);
          clearTimeout(scrollTmr);

          const vv = window.visualViewport;

          keyboardBaseH = vv ? vv.height : window.innerHeight;
          keyboardMinH = keyboardBaseH;
          keyboardWasOpen = false;
          keyboardReadyAt = Date.now() + 400; // затримка перед перевіркою
          armContactInputJumpProbe(field);
          return;
        }

        // якщо фокусу в полі немає — нічого не робимо
        if (!isFormFieldFocused()) return;

        // тап всередині форми — не blur
        if (formEl && formEl.contains(target)) return;

        // тап поза формою — blur
        blurFocusedFormField();
        clearContactInputJumpProbe();
      },
      true,
    );

    document.addEventListener(
      'focusin',
      e => {
        const target = e.target instanceof Element ? e.target : null;
        if (!target) return;

        const formEl = document.getElementById('contact-section-form');
        if (!formEl || !formEl.contains(target)) return;
        if (!isMobileOrTablet()) return;
        if (window.__contactInputModalModeEnabled === true) return;
        if (!isFormField(target)) return;

        armContactInputJumpProbe(target);
      },
      true,
    );
  }

  document.addEventListener(
    'keydown',
    e => {
      if (e.key !== 'Escape') return;
      e.preventDefault();
      e.stopPropagation();

      blurFocusedFormField();
      clearContactInputJumpProbe();
    },
    true,
  );

  // ---------- ПУБЛІЧНИЙ МІНІ-API ----------
  window.fullpage = {
    goToId(idOrHash) {
      const id = idOrHash.startsWith('#') ? idOrHash : `#${idOrHash}`;

      const target = document.querySelector(id);
      if (!target) return;
      const sec = target.closest('.section') || target;
      const idx = sections.indexOf(sec);
      if (idx >= 0 && !locked) lockAndGo(idx);
    },
    goToIndex(i) {
      if (i >= 0 && i < stops.length && !locked) lockAndGo(i);
    },
  };

  // ---------- ІНІЦІАЛІЗАЦІЯ ----------
  try {
    document.documentElement.style.scrollBehavior = 'auto';
  } catch {}

  ensureScalingWrappers();
  applyFitScalesOnce();
  init();
  buildSideNav();
  setActiveSidebar(current);
  setActiveHeader(current);
  updateActiveSection();
  bootToHashIfAny();

  // ---------- ЛІСТЕНЕРИ ----------
  window.addEventListener('wheel', onWheel, { passive: false });
  window.addEventListener('keydown', onKey);
  wireAnchors();
  wireTouch();

  window.addEventListener(
    'resize',
    () => {
      detectContactInputJumpAndEnableFallback('win-resize');
      if (shouldPauseFullpage()) return;
      clearTimeout(resizeTimer);

      resizeTimer = setTimeout(() => {
        if (shouldPauseFullpage()) return;
        syncToFixedSectionAfterViewportChange(false);
        scheduleSectionPlacementRepair(60, 'resize-post-sync');
      }, 120);
    },
    { passive: true },
  );

  window.addEventListener('contact-input-modal:open', () => {
    // Підстрахуємо snap, коли модалка відкривається не вперше (вже в fallback mode)
    requestAnimationFrame(() => {
      snapToContactSectionNoAnim();
      setTimeout(() => snapToContactSectionNoAnim(), 90);
    });
  });

  window.addEventListener('contact-input-modal:before-close', () => {
    // Поки модалка ще на екрані — повертаємо fullpage на contact
    snapToContactSectionNoAnim();
    setTimeout(() => snapToContactSectionNoAnim(), 60);
  });

  window.addEventListener('contact-input-modal:close', () => {
    // Після закриття модалки/клавіатури viewport ще може "дихати" — чекаємо трохи і доснапуємо
    queueSnapToContactSection(40);
    setTimeout(() => {
      if (window.__contactInputModalOpen) return;
      snapToContactSectionNoAnim();
    }, 140);
  });

  window.addEventListener(
    'orientationchange',
    () => {
      setTimeout(() => {
        if (shouldPauseFullpage()) return;
        syncToFixedSectionAfterViewportChange(true);
        scheduleSectionPlacementRepair(100, 'orientation-post-sync');
      }, 150);
    },
    { passive: true },
  );

  // Головне: усі зміни хешу веде наш скролер (без нативного стрибка)
  window.addEventListener('hashchange', () => {
    if (shouldPauseFullpage()) return;
    const id = location.hash;
    if (!id || id.length <= 1) return;
    // утримаємо позицію (на випадок якщо браузер таки смикнеться)
    const keepY = window.scrollY;
    window.scrollTo(0, keepY);
    window.fullpage.goToId(id);
  });

  window.addEventListener(
    'scroll',
    () => {
      if (locked) return;
      detectContactInputJumpAndEnableFallback('scroll');
      if (shouldPauseFullpage()) return;

      clearTimeout(scrollTmr);
      scrollTmr = setTimeout(() => {
        updateActiveSection();
        scheduleSectionPlacementRepair(0, 'scroll-end');
      }, 60);
    },
    { passive: true },
  );

  window.addEventListener('load', () => {
    init();
    updateActiveSection();
    scheduleSectionPlacementRepair(120, 'load');
  });

  window.addEventListener('pageshow', e => {
    // при поверненні з кешу історії переконаємось, що хеш відпрацьовано
    if (e.persisted) bootToHashIfAny();
    scheduleSectionPlacementRepair(120, 'pageshow');
  });

  window.visualViewport?.addEventListener('resize', () => {
    blurOnKeyboardClose();
    detectContactInputJumpAndEnableFallback('vv-resize');
    if (!shouldPauseFullpage())
      scheduleSectionPlacementRepair(120, 'vv-resize');
  });

  document.querySelectorAll('img').forEach(img => {
    if (!img.complete) {
      img.addEventListener('load', () => scheduleImageLoadRecalc(), {
        once: true,
      });
    }
  });
})();

